import { describe, expect, it } from "vitest";

import { bounds, config } from "../../config/index.js";
import type { EnemyDefinition } from "../../schemas/entities/index.js";
import { validEnemyDefinitionFixture } from "../../schemas/fixtures/entities.js";
import {
  createFloorGeometrySlot,
  createTile,
  createTileGrid,
  Terrain,
  withTile,
} from "../map/index.js";
import {
  ACTIVE_TERMINAL_STATUS,
  depthBandForDepth,
  serialize,
  type EnemyEntityInstance,
  type EntityId,
  type GameState,
  type Position,
} from "../state/index.js";
import {
  TICK_HOOK_ORDER,
  getAvailableActions,
  isTerminal,
  render,
  start,
  step,
  type TickHookName,
  type TurnEvent,
} from "./loop.js";

describe("turn loop public contract", () => {
  it("starts seeded runs by delegating to state initialization", () => {
    const state = start("turn-contract");

    expect(state.run.seed).toBe("turn-contract");
    expect(state.run.turn).toBe(0);
    expect(state.run.terminalStatus).toBe(ACTIVE_TERMINAL_STATUS);
  });

  it("exposes available actions through the stable loop API", () => {
    const actions = getAvailableActions(start("available-contract"));

    expect(actions).toEqual([{ kind: "wait" }, { kind: "abort" }]);
  });

  it("steps valid actions through player, actor, and tick phases", () => {
    const result = step(start("step-contract"), { kind: "wait" });

    expect(result.state.run.turn).toBe(1);
    expect(result.events.map((event) => event.type)).toEqual([
      "action_resolved",
      "tick_hook",
      "tick_hook",
      "tick_hook",
      "tick_hook",
    ]);
  });

  it("renders a minimal deterministic debug string", () => {
    expect(render(start("render-contract"))).toBe(
      "run=run#render-contract turn=0 depth=1 status=ACTIVE player=(0,0) hp=20/20",
    );
  });

  it("reports terminal state from explicit run status", () => {
    const active = start("terminal-contract");
    const won = {
      ...active,
      run: {
        ...active.run,
        terminalStatus: config.runStructure.terminalStates.win,
      },
    };

    expect(isTerminal(active)).toBe(false);
    expect(isTerminal(won)).toBe(true);
  });
});

describe("invalid and terminal action handling", () => {
  it("returns typed errors and zero state change for invalid actions", () => {
    const state = start("invalid-noop");
    const before = serialize(state);
    const result = step(state, { kind: "move", direction: "north" });

    expect(serialize(result.state)).toBe(before);
    expect(result.state.run.turn).toBe(0);
    expect(result.events).toEqual([
      {
        turn: 0,
        type: "action_illegal",
        data: {
          actionKind: "move",
          reason: "floor geometry is not loaded",
        },
      },
    ]);
  });

  it("leaves terminal states unchanged and returns an illegal-action event", () => {
    const terminal = {
      ...start("terminal-noop"),
      run: {
        ...start("terminal-noop").run,
        terminalStatus: config.runStructure.terminalStates.win,
      },
    };
    const before = serialize(terminal);
    const result = step(terminal, { kind: "wait" });

    expect(serialize(result.state)).toBe(before);
    expect(result.events).toEqual([
      {
        turn: 0,
        type: "action_illegal",
        data: {
          actionKind: "wait",
          reason: "run is terminal (WIN)",
        },
      },
    ]);
  });

  it("forces loss at the configured hard cap", () => {
    const state = {
      ...start("hard-cap"),
      run: {
        ...start("hard-cap").run,
        turn: bounds.runStructure.perRunHardCapTurns - 1,
      },
    };

    const result = step(state, { kind: "wait" });

    expect(result.state.run.turn).toBe(bounds.runStructure.perRunHardCapTurns);
    expect(result.state.run.terminalStatus).toBe(
      config.runStructure.terminalStates.loss,
    );
    expect(result.events.at(-1)).toEqual({
      turn: bounds.runStructure.perRunHardCapTurns,
      type: "terminal_state",
      data: {
        status: "LOSS",
        reason: `run hard cap reached at ${bounds.runStructure.perRunHardCapTurns} turns`,
      },
    });
  });

  it("makes win, loss, and aborted terminal states reachable", () => {
    const aborted = step(start("aborted-terminal"), { kind: "abort" }).state;
    const loss = step(withPlayerHp(start("loss-terminal"), 0), {
      kind: "wait",
    }).state;
    const win = step(finalFloorStairsState("win-terminal"), {
      kind: "descend",
    }).state;

    expect(aborted.run.terminalStatus).toBe(
      config.runStructure.terminalStates.abort,
    );
    expect(loss.run.terminalStatus).toBe(config.runStructure.terminalStates.loss);
    expect(win.run.terminalStatus).toBe(config.runStructure.terminalStates.win);
  });
});

describe("turn ordering hooks", () => {
  it("runs actor no-op hooks in stable actor-id order over 100 turns", () => {
    let state = withEntities(start("actor-order"), [
      enemy("enemy#3", { x: 3, y: 0 }),
      enemy("enemy#1", { x: 1, y: 0 }),
      enemy("enemy#2", { x: 2, y: 0 }),
    ]);
    const seen: EntityId[] = [];

    for (let index = 0; index < 100; index += 1) {
      const result = step(state, { kind: "wait" }, {
        hooks: {
          actorTurn: ({ actor, state: hookState }) => {
            seen.push(actor.id);
            return hookState;
          },
        },
      });
      state = result.state;
    }

    expect(seen).toHaveLength(300);
    for (let index = 0; index < seen.length; index += 3) {
      expect(seen.slice(index, index + 3)).toEqual([
        "enemy#1",
        "enemy#2",
        "enemy#3",
      ]);
    }
  });

  it("runs tick hooks in fixed GAME_DESIGN order", () => {
    const seen: TickHookName[] = [];
    const result = step(start("tick-order"), { kind: "wait" }, {
      hooks: {
        ticks: {
          damageOverTime: ({ hook, state }) => {
            seen.push(hook);
            return state;
          },
          durations: ({ hook, state }) => {
            seen.push(hook);
            return state;
          },
          hunger: ({ hook, state }) => {
            seen.push(hook);
            return state;
          },
          regen: ({ hook, state }) => {
            seen.push(hook);
            return state;
          },
        },
      },
    });

    expect(seen).toEqual(TICK_HOOK_ORDER);
    expect(result.events.filter(isTickHookEvent).map((event) => event.data.hook)).toEqual(
      TICK_HOOK_ORDER,
    );
  });
});

const withPlayerHp = (state: GameState, hp: number): GameState => ({
  ...state,
  player: {
    ...state.player,
    hp: {
      ...state.player.hp,
      current: hp,
    },
  },
});

const withEntities = (
  state: GameState,
  entities: readonly EnemyEntityInstance[],
): GameState => ({
  ...state,
  entities: Object.fromEntries(entities.map((entity) => [entity.id, entity])),
});

const finalFloorStairsState = (seed: string): GameState => {
  const depth = config.runStructure.depthFloors;
  const band = depthBandForDepth(depth);
  const grid = withTile(
    createTileGrid({ width: 1, height: 1 }),
    { x: 0, y: 0 },
    createTile(Terrain.StairsDown),
  );
  const state = start(seed);

  return {
    ...state,
    run: {
      ...state.run,
      depth,
      band,
    },
    floor: {
      ...state.floor,
      floorId: `floor#${depth}`,
      depth,
      band,
      geometry: createFloorGeometrySlot(`floor-geometry#${depth}`, grid),
    },
    player: {
      ...state.player,
      position: { x: 0, y: 0 },
    },
  };
};

const enemy = (id: EntityId, position: Position): EnemyEntityInstance => ({
  id,
  kind: "enemy",
  definition: validEnemyDefinitionFixture as unknown as EnemyDefinition,
  position,
  currentHP: validEnemyDefinitionFixture.stats.hp,
  statuses: [],
  behaviorRuntime: {},
});

const isTickHookEvent = (
  event: TurnEvent,
): event is Extract<TurnEvent, { readonly type: "tick_hook" }> =>
  event.type === "tick_hook";

/*
 * PHASE-07B FROZEN TURN HOOK INTERFACE
 *
 * A turn always resolves in this order:
 * 1. the player action resolves;
 * 2. every other actor runs exactly once in stable actor-id order;
 * 3. end-of-turn tick hooks run in this fixed order:
 *    damageOverTime -> durations -> hunger -> regen.
 *
 * Later phases register combat/AI/status/hunger/regen behavior through TurnHooks.
 * Do not rename TickHookName values, reorder TICK_HOOK_ORDER, or let hooks call
 * ambient nondeterminism or LLMs. Hooks must return deterministic state/events.
 */

import { bounds, config, type GameConfig } from "../../config/index.js";
import { createClock } from "../clock/index.js";
import {
  ACTIVE_TERMINAL_STATUS,
  createInitialState,
  type EngineLogEvent,
  type EntityId,
  type EntityInstance,
  type GameState,
  type TerminalStatus,
} from "../state/index.js";
import {
  checkActionLegality,
  type PlayerAction,
} from "./actions.js";

declare module "../state/types.js" {
  interface EngineLogEventDataByType {
    readonly action_illegal: {
      readonly actionKind: PlayerAction["kind"];
      readonly reason: string;
    };
    readonly action_resolved: {
      readonly actionKind: PlayerAction["kind"];
    };
    readonly actor_turn: {
      readonly actorId: EntityId;
    };
    readonly tick_hook: {
      readonly hook: TickHookName;
    };
    readonly terminal_state: {
      readonly status: Exclude<TerminalStatus, "ACTIVE">;
      readonly reason: string;
    };
  }
}

export { checkActionLegality, getAvailableActions } from "./actions.js";
export type {
  AbortAction,
  ActionLegality,
  ActionTarget,
  AttackAction,
  DescendAction,
  InspectAction,
  MoveAction,
  MoveDirection,
  PickupAction,
  PlayerAction,
  TalkAction,
  UseItemAction,
  WaitAction,
} from "./actions.js";

export type TurnEvent = EngineLogEvent;

export type ActorEntity = Extract<EntityInstance, { readonly kind: "enemy" | "npc" }>;

export type TickHookName =
  | "damageOverTime"
  | "durations"
  | "hunger"
  | "regen";

export const TICK_HOOK_ORDER = [
  "damageOverTime",
  "durations",
  "hunger",
  "regen",
] as const satisfies readonly TickHookName[];

export type TurnHookResult =
  | GameState
  | {
      readonly state: GameState;
      readonly events?: readonly TurnEvent[];
    };

export type ActorTurnHook = (context: {
  readonly state: GameState;
  readonly actor: ActorEntity;
  readonly action: PlayerAction;
}) => TurnHookResult;

export type TickHook = (context: {
  readonly state: GameState;
  readonly hook: TickHookName;
  readonly action: PlayerAction;
}) => TurnHookResult;

export type TickHooks = {
  readonly [Hook in TickHookName]: TickHook;
};

export type TurnHooks = {
  readonly actorTurn?: ActorTurnHook;
  readonly ticks?: Partial<TickHooks>;
};

export type ResolvedTurnHooks = {
  readonly actorTurn: ActorTurnHook;
  readonly ticks: TickHooks;
};

export type StepOptions = {
  readonly hooks?: TurnHooks;
};

export type StepResult = {
  readonly state: GameState;
  readonly events: readonly TurnEvent[];
};

export type StartContent = {
  readonly config?: GameConfig;
};

export const start = (seed: string, content: StartContent = {}): GameState =>
  createInitialState(seed, content.config ?? config);

export const step = (
  state: GameState,
  action: PlayerAction,
  options: StepOptions = {},
): StepResult => {
  if (isTerminal(state)) {
    return illegalStep(
      state,
      action,
      `run is terminal (${state.run.terminalStatus})`,
    );
  }

  const legality = checkActionLegality(state, action);
  if (legality.status === "illegal") {
    return illegalStep(state, action, legality.reason);
  }

  const forcedTerminal = forcedTerminalFor(state);
  if (forcedTerminal !== null) {
    return terminalStep(state, forcedTerminal.status, forcedTerminal.reason);
  }

  const hooks = resolveTurnHooks(options.hooks);
  const events: TurnEvent[] = [
    turnEvent(state.run.turn, "action_resolved", {
      actionKind: action.kind,
    }),
  ];

  let nextState = state;
  const playerActionResult = applyPlayerAction(nextState, action);
  nextState = playerActionResult.state;
  events.push(...playerActionResult.events);

  if (!isTerminal(nextState)) {
    for (const actor of actorsInTurnOrder(nextState)) {
      events.push(
        turnEvent(nextState.run.turn, "actor_turn", {
          actorId: actor.id,
        }),
      );

      const result = normalizeHookResult(
        hooks.actorTurn({
          state: nextState,
          actor,
          action,
        }),
      );
      nextState = result.state;
      events.push(...result.events);

      if (isTerminal(nextState)) {
        break;
      }
    }
  }

  if (!isTerminal(nextState)) {
    for (const hook of TICK_HOOK_ORDER) {
      events.push(
        turnEvent(nextState.run.turn, "tick_hook", {
          hook,
        }),
      );

      const result = normalizeHookResult(
        hooks.ticks[hook]({
          state: nextState,
          hook,
          action,
        }),
      );
      nextState = result.state;
      events.push(...result.events);

      if (isTerminal(nextState)) {
        break;
      }
    }
  }

  if (!isTerminal(nextState)) {
    nextState = advanceTurn(nextState);

    const terminal = forcedTerminalFor(nextState);
    if (terminal !== null) {
      nextState = withTerminalStatus(nextState, terminal.status);
      events.push(
        turnEvent(nextState.run.turn, "terminal_state", {
          status: terminal.status,
          reason: terminal.reason,
        }),
      );
    }
  }

  nextState = appendLog(nextState, events);

  return {
    state: nextState,
    events,
  };
};

export const render = (state: GameState): string =>
  [
    `run=${state.run.runId}`,
    `turn=${state.run.turn}`,
    `depth=${state.run.depth}`,
    `status=${state.run.terminalStatus}`,
    `player=(${state.player.position.x},${state.player.position.y})`,
    `hp=${state.player.hp.current}/${state.player.hp.max}`,
  ].join(" ");

export const isTerminal = (state: GameState): boolean =>
  state.run.terminalStatus !== ACTIVE_TERMINAL_STATUS;

export const createNoopTurnHooks = (): ResolvedTurnHooks => ({
  actorTurn: ({ state }) => state,
  ticks: {
    damageOverTime: ({ state }) => state,
    durations: ({ state }) => state,
    hunger: ({ state }) => state,
    regen: ({ state }) => state,
  },
});

const applyPlayerAction = (
  state: GameState,
  action: PlayerAction,
): StepResult => {
  if (action.kind === "abort") {
    const status = config.runStructure.terminalStates.abort;
    const terminalState = withTerminalStatus(state, status);

    return {
      state: terminalState,
      events: [
        turnEvent(state.run.turn, "terminal_state", {
          status,
          reason: "player aborted the run",
        }),
      ],
    };
  }

  if (
    action.kind === "descend" &&
    state.run.depth >= config.runStructure.depthFloors
  ) {
    const status = config.runStructure.terminalStates.win;
    const terminalState = withTerminalStatus(state, status);

    return {
      state: terminalState,
      events: [
        turnEvent(state.run.turn, "terminal_state", {
          status,
          reason: "player descended from the final floor",
        }),
      ],
    };
  }

  return {
    state,
    events: [],
  };
};

const forcedTerminalFor = (
  state: GameState,
): { readonly status: Exclude<TerminalStatus, "ACTIVE">; readonly reason: string } | null => {
  if (state.player.hp.current <= 0) {
    return {
      status: config.runStructure.terminalStates.loss,
      reason: "player HP reached 0",
    };
  }

  if (state.run.turn >= bounds.runStructure.perRunHardCapTurns) {
    return {
      status: config.runStructure.terminalStates.loss,
      reason: `run hard cap reached at ${bounds.runStructure.perRunHardCapTurns} turns`,
    };
  }

  return null;
};

const terminalStep = (
  state: GameState,
  status: Exclude<TerminalStatus, "ACTIVE">,
  reason: string,
): StepResult => {
  const event = turnEvent(state.run.turn, "terminal_state", {
    status,
    reason,
  });
  const terminalState = appendLog(withTerminalStatus(state, status), [event]);

  return {
    state: terminalState,
    events: [event],
  };
};

const illegalStep = (
  state: GameState,
  action: PlayerAction,
  reason: string,
): StepResult => ({
