const resolveTurnHooks = (hooks: TurnHooks | undefined): ResolvedTurnHooks => {
  const noopHooks = createNoopTurnHooks();

  return {
    actorTurn: hooks?.actorTurn ?? noopHooks.actorTurn,
    ticks: {
      ...noopHooks.ticks,
