};

const normalizeHookResult = (
  result: TurnHookResult,
): { readonly state: GameState; readonly events: readonly TurnEvent[] } => {
  if (isHookResultEnvelope(result)) {
    return {
      state: result.state,
      events: result.events ?? [],
    };
  }

  return {
    state: result,
    events: [],
